import{_ as t,o as n,c as s,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"行业专项模板库","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/index.md","filePath":"zh/industry/index.md"}'),d={name:"zh/industry/index.md"};function r(i,a,l,p,o,h){return n(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="行业专项模板库" tabindex="-1">行业专项模板库 <a class="header-anchor" href="#行业专项模板库" aria-label="Permalink to &quot;行业专项模板库&quot;">​</a></h1><p>通用模板提供框架，但不同行业的风险画像差异显著——服装厂关注工时与童工，化工企业关注危废排放，软件供应商关注数据安全与知识产权。</p><p>本库按行业提供深度定制的评估工具，每套工具均包含：行业专项SAQ、审核前文件清单、关键访谈问题，以及该行业历史案例参照。</p><h2 id="可用行业模板" tabindex="-1">可用行业模板 <a class="header-anchor" href="#可用行业模板" aria-label="Permalink to &quot;可用行业模板&quot;">​</a></h2><table tabindex="0"><thead><tr><th>行业</th><th>主要风险领域</th><th>完成度</th></tr></thead><tbody><tr><td><a href="./garment/">服装与纺织</a></td><td>劳工（加班/童工）、化学品（REACH）、分包隐瞒</td><td>✅ 完整</td></tr><tr><td><a href="./electronics/">消费电子与代工</a></td><td>矿产溯源（冲突矿产）、数据安全、劳工</td><td>✅ 完整</td></tr><tr><td><a href="./food/">食品与农业</a></td><td>食品安全、农业劳工、用水管理、EUDR</td><td>✅ 完整</td></tr><tr><td><a href="./chemicals/">化工与危险品</a></td><td>危废管理、REACH/GHS、职业健康</td><td>✅ 完整</td></tr><tr><td><a href="./construction/">建筑与工程</a></td><td>建筑安全、分包层级、反腐败</td><td>✅ 完整</td></tr></tbody></table><h2 id="如何选择模板" tabindex="-1">如何选择模板 <a class="header-anchor" href="#如何选择模板" aria-label="Permalink to &quot;如何选择模板&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>供应商类型？</span></span>
<span class="line"><span>├─ 生产型（工厂）→ 选择对应行业 SAQ</span></span>
<span class="line"><span>├─ 贸易商/中间商 → 使用通用 SAQ Section A+B</span></span>
<span class="line"><span>└─ 服务型（IT/物流/咨询）→ 使用通用 SAQ Section A+G</span></span>
<span class="line"><span></span></span>
<span class="line"><span>风险等级？</span></span>
<span class="line"><span>├─ 高风险（高关注度地区 + 核心供应商）→ 完整现场审核 + 全量SAQ</span></span>
<span class="line"><span>├─ 中风险 → 文件审核 + 重点章节SAQ</span></span>
<span class="line"><span>└─ 低风险 → SAQ自评 + 抽查</span></span></code></pre></div><h2 id="与通用模板的关系" tabindex="-1">与通用模板的关系 <a class="header-anchor" href="#与通用模板的关系" aria-label="Permalink to &quot;与通用模板的关系&quot;">​</a></h2><p>行业专项模板<strong>补充</strong>通用模板，不替代。推荐使用方式：</p><ol><li><strong>通用 SAQ</strong>（<a href="/zh/templates/saq.html">Section A–H</a>）作为基础筛查</li><li>根据供应商行业叠加对应的<strong>行业专项模块</strong></li><li>审核前文件请求使用<strong>行业专项清单</strong>替代通用清单</li></ol>`,10)])])}const _=t(d,[["render",r]]);export{u as __pageData,_ as default};
